#include <bits/stdc++.h>
using namespace std;
map<pair<int,int>,int> c;
map<int,int> id;
int a[5],dp[202][202],n;
string name;
int main(){
	id['W']=1,id['I']=2,id['N']=3,id['G']=4;
	for(int i=1;i<=4;i++)
		scanf("%d",&a[i]);
	string s;
	for(int i=1;i<=4;i++)
		for(int j=1;j<=a[i];j++){
			cin>>s;
			c[make_pair(id[s[0]],id[s[1]])]|=(1<<i);
		}
	cin>>name;
	n=name.size(),name=" "+name;
	for(int i=1;i<=n;i++)
		dp[i][i]=(1<<id[name[i]]);
	for(int len=2;len<=n;len++)
		for(int l=1;l+len-1<=n;l++){
			int r=l+len-1;
			for(int k=l;k<r;k++)
				for(int a=1;a<=4;a++)
					for(int b=1;b<=4;b++)
						if(dp[l][k]&(1<<a) && dp[k+1][r]&(1<<b) && c[make_pair(a,b)])
							for(int t=1;t<=4;t++)
								if(c[make_pair(a,b)]&(1<<t))
									dp[l][r]|=(1<<t);
		}
	if(dp[1][n]==0)
		printf("The name is wrong!");
	else{
		if(dp[1][n]&2)
			printf("W");
		if(dp[1][n]&4)
			printf("I");
		if(dp[1][n]&8)
			printf("N");
		if(dp[1][n]&16)
			printf("G");
	}
	return 0;
}
